              "type": "object",
              "properties": {
                "coding": {
                  "type": "array",
                  "items": {
                    "type": "object",
                    "properties": {
                      "system": {
                        "type": "string",
                        "description": "Coding system such as \"http://hl7.org/fhir/sid/ndc\" "
                      },
                      "code": {
                        "type": "string",
                        "description": "The actual code"
                      },
