                        "type": "string",
                        "description": "Display name"
                      }
                    }
                  }
                },
                "text": {
                  "type": "string",
                  "description": "The order display name of the medication, otherwise the record name."
                }
              }
            },
            "authoredOn": {
              "type": "string",
              "description": "The date the prescription was written."
            },
            "dosageInstruction": {
              "type": "array",
