              "description": "Any part of the patient's name. When discrete name parameters are used, such as family or given, this parameter is ignored."
            },
            "telecom": {
              "type": "string",
              "description": "The patient's phone number or email."
            }
          },
          "required": []
        }
      }
    ]
  },
  "response_format": {
    "type": "api_action",
    "options": [
